mapper.select:
SELECT pcg.id, pcg.patient_id AS patientId, p.patient_name AS patientName, pcg.medical_record_id AS medicalRecordId, mr.record_no AS medicalRecordNo, pcg.group_name AS groupName, pcg.pre_image_id AS preImageId, preFile.file_url AS preImageUrl, pcg.post_image_id AS postImageId, postFile.file_url AS postImageUrl, pcg.compare_desc AS compareDesc, pcg.created_by AS createdBy, pcg.created_at AS createdAt FROM photo_compare_group pcg LEFT JOIN patient p ON p.id = pcg.patient_id LEFT JOIN medical_record mr ON mr.id = pcg.medical_record_id LEFT JOIN patient_image pre ON pre.id = pcg.pre_image_id LEFT JOIN file_attachment preFile ON preFile.id = pre.file_id LEFT JOIN patient_image post ON post.id = pcg.post_image_id LEFT JOIN file_attachment postFile ON postFile.id = post.file_id WHERE p.org_id = #{orgId}
AND pcg.patient_id = #{query.patientId}
AND pcg.medical_record_id = #{query.medicalRecordId}
ORDER BY pcg.created_at DESC, pcg.id DESC
